function buildReadingSets(): ReadingSet[] {
    const bySet = new Map<string, ReadingSet>();
    for (const key of Object.keys(readingTestsWithPassages)) {
        const row = readingTestsWithPassages[key];
        const setId = row.examId;
        if (!bySet.has(setId)) {
            bySet.set(setId, {
                id: setId,
                title: row.title,
                examLabel: row.examLabel,
                cambridgeNumber: row.cambridgeNumber,
                variant: row.variant,
                tests: [],
            });
        }
        bySet.get(setId)!.tests.push({
            id: row.id,
            label: row.label,
            testNumber: row.testNumber,
        });
    }
    return Array.from(bySet.values())
        .sort((a, b) => b.cambridgeNumber - a.cambridgeNumber)
        .map((s) => ({
        ...s,
        tests: [...s.tests].sort((a, b) => a.testNumber - b.testNumber),
    }));
}
export const readingSets: ReadingSet[] = buildReadingSets();
export function getReadingSet(setId: string): ReadingSet | undefined {
    return readingSets.find((s) => s.id === setId);
}
export function getReadingTest(setId: string, testId: string): ReadingTestResolved | undefined {
    const set = getReadingSet(setId);
    if (!set)
        return undefined;
    const test = set.tests.find((t) => t.id === testId);
    if (!test)
        return undefined;
    const key = `${setId}|${testId}`;
    const raw = engnovateReadingAnswers[key];
    const correctAnswers = raw
        ? (Object.fromEntries(Object.entries(raw).map(([k, v]) => [Number(k), v])) as Record<number, ReadingAnswer>)
        : undefined;
    return { ...test, correctAnswers, set };
}
